+@Component
+struct FileListView {
+  private startModeOptions: StartModeOptions;
+  @Link fileListSource: FileDataSource;
+  @Link direList: BreadData[];
+  @Link isMulti: boolean;
+  @Link checkedNum: number;
+
+  build() {
+    List() {
+      LazyForEach(this.fileListSource, (item: FilesData, index: number) => {
